using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.Diagnostics;

class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // Preserve EF8 discriminator property name (EF9 defaults to "$type")
        modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

        // Preserve EF8 id format: "Blog|{key}" (EF9 defaults to key-only)
        modelBuilder.Entity<Blog>().HasDiscriminatorInJsonId();

        // Preserve EF8 shadow __id property (EF9 maps key directly to JSON "id")
        modelBuilder.Entity<Blog>().HasShadowId();

        // HasIndex removed — Cosmos indexes all properties by default; EF9 now throws.
    }
}

